(107, 6, '[FB] ป.1 สอนแต่งประโยค ประธาน กริยา กรรม', '1765471470_ประโยค RT เทคนิคดีๆค่า v2.mp4', 'cda11up', '1765471470_ประโยค RT เทคนิคดีๆค่า pic.jpg', '5:19', '<p>[FB] ป.1 สอนแต่งประโยค ประธาน กริยา กรรม</p>\r\n\r\n<p><img alt=\"\" src=\"data:image/jpeg;base64,', 'Upload', 1, '38.73 MB', 11, '2025-12-11 09:44:30');
INSERT INTO `tbl_gallery` (`id`, `cat_id`, `video_title`, `video_url`, `video_id`, `video_thumbnail`, `video_duration`, `video_description`, `video_type`, `video_status`, `size`, `total_views`, `date_time`) VALUES
(108, 6, '[Facebook ]สื่อสำหรับเด็กปฐมวัย', '1765472651_media_for_early_childhood_education_video.mp4', 'cda11up', '1765472651_สื่อสำหรับเด็กปฐมวัย pic .jpg', '5:16', '<p>สื่อสำหรับเด็กปฐมวัย</p>\r\n\r\n<p>สื่อของเด็กคืออะไร ทำไมเด็กต้องเล่นของเล่น? การเรียนรู้เกิดจากการเล่นได้จริงหรือ?&nbsp;แล้วสื่อออนไลน์ใช่สิ่งที่เหมาะสำหรับเด็กหรือไม่?</p>\r\n\r\n<p>.</p>\r\n\r\n<p>TK Team ชวน อาจารย์ ดร.พรพิมล รอดเคราะห์ ผู้ช่วยหัวหน้าภาคหลักสูตรและวิธีสอน ฝ่ายเทคโนโลยีและนวัตกรรม คณะศึกษาศาสตร์ มหาวิทยาลัยศิลปากร ผู้เชี่ยวชาญด้านการออกแบบ และพัฒนานวัตกรรมสื่อการเรียนการสอน และการพัฒนาเกมดิจิทัลเพื่อการศึกษาสำหรับเด็ก สู่การนำไปปรับใช้และสร้างสรรค์สื่อการเรียนรู้ที่เหมาะสมสำหรับเด็ก มาเฉลยว่าสื่อที่เหมาะสมสำหรับเด็กปฐมวัยยุคนี้คือสิ่งใด และเราจะมีวิธีผลิตสื่อได้อย่างไร</p>\r\n\r\n<p>.</p>\r\n\r\n<p><a href=\"https://www.facebook.com/watch/hashtag/tkpark?__eep__=6%2F&amp;__tn__=*NK-R\">#TKPark</a>&nbsp;<a href=\"https://www.facebook.com/watch/hashtag/%E0%B9%81%E0%B8%AD%E0%B8%9B?__eep__=6%2F&amp;__tn__=*NK-R\">#แอป</a>&nbsp;<a href=\"https://www.facebook.com/watch/hashtag/%E0%B8%AA%E0%B8%B7%E0%B9%88%E0%B8%AD%E0%B8%81%E0%B8%B2%E0%B8%A3%E0%B8%AA%E0%B8%AD%E0%B8%99?__eep__=6%2F&amp;__tn__=*NK-R\">#สื่อการสอน</a>&nbsp;<a href=\"https://www.facebook.com/watch/hashtag/%E0%B9%80%E0%B8%94%E0%B9%87%E0%B8%81?__eep__=6%2F&amp;__tn__=*NK-R\">#เด็ก</a>&nbsp;<a href=\"https://www.facebook.com/watch/hashtag/%E0%B9%80%E0%B8%94%E0%B9%87%E0%B8%81%E0%B8%9B%E0%B8%90%E0%B8%A1%E0%B8%A7%E0%B8%B1%E0%B8%A2?__eep__=6%2F&amp;__tn__=*NK-R\">#เด็กปฐมวัย</a></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>cr :&nbsp;</p>\r\n\r\n<h2><a href=\"https://www.facebook.com/tkparkclub?__tn__=-UC-R\"><strong>TK Park อุทยานการเรียนรู้</strong></a>&nbsp;</h2>\r\n\r\n<p>&nbsp;</p>\r\n', 'Upload', 1, '42.87 MB', 22, '2025-12-11 10:04:11'),
(109, 6, '[Facebook] ตอนที่ ๑ การอ่านนั้นสำคัญอย่างไร\\\"ปลุกสมรรถนะการอ่าน ปลุกการเรียนรู้สู่การพัฒนาสมรรถนะการอ่านขั้นสูง\\\" ', '1765474024_AQMzxk56puRdXQnM27UlHx1auIlnsuL3wqmi7ljwR2wyyB9_yhy0mOeWdDMtw_Kw2WsYwfZGJyiaISkdRknyHA.mp4', 'cda11up', '1765474024_294446435_1482807195494160_7227256804394614254_n.jpg', '14:30', '<p><img alt=\"\" src=\"https://scontent.fhan5-6.fna.fbcdn.net/v/t15.13418-10/294446435_1482807195494160_7227256804394614254_n.jpg?stp=dst-jpg_s526x296_tt6&amp;_nc_cat=105&amp;ccb=1-7&amp;_nc_sid=1727f7&amp;_nc_ohc=yvObbcX31coQ7kNvwEN7dwP&amp;_nc_oc=AdlwsXPxL-XkHWia1hoFV3RBpsYMsgSjGc8LOcdn22bQzJZXNbh8wBoCbRXbpErsNl0&amp;_nc_zt=23&amp;_nc_ht=scontent.fhan5-6.fna&amp;edm=AGo2L-IEAAAA&amp;_nc_gid=UyfopJHZarqHHHwHdJfTfQ&amp;oh=00_AfNKr7uNCQ1zSsykE3weSs1ng2ev4z4Rxh0DFFC1EIuJHg&amp;oe=685A1A0F\" /></p>\r\n\r\n<p>ตอนที่ ๑ การอ่านนั้นสำคัญอย่างไร&quot;ปลุกสมรรถนะการอ่าน ปลุกการเรียนรู้สู่การพัฒนาสมรรถนะการอ่านขั้นสูง&quot;&nbsp;ด้วยวีดิทัศน์การพัฒนาสมรรถนะการอ่านขั้นสูงสำหรับนักเรียนชั้นมัธยมศึกษาตอนต้นผ่านการจัดการเรียนรู้เชิงรุก (Active Learning)&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>cr :&nbsp;https://web.facebook.com/thaiobec/videos/859913668323804</p>\r\n\r\n<h2><a href=\"https://web.facebook.com/thaiobec?__tn__=-UC-R\"><strong>สถาบันภาษาไทย สำนักวิชาการและมาตรฐานการศึกษา สพฐ.</strong></a></h2>\r\n\r\n<p>&nbsp;</p>\r\n', 'Upload', 1, '10.95 MB', 6, '2025-12-11 10:27:04'),
(112, 6, 'ตอนที่ ๒ อ่านเรื่องให้จบ\\\" ปลุกสมรรถนะการอ่าน ปลุกการเรียนรู้สู่การพัฒนาสมรรถนะการอ่านขั้นสูง\\\"', '1765474952_AQMson16Ad2noPnmjCR-AZaIaJPz_VVBTogyg00HwHcLTFjvPC0FzeuLj1bAn1_Pf2wG0r0UVBJk9tDpcjFLmT68iMAO40ac6DXP9I4LZUB0YA.mp4', 'cda11up', '1765474952_294903033_152145174070799_3887817956404413795_n.jpg', '14:20', '<h2>&nbsp;</h2>\r\n\r\n<p>ตอนที่ ๒ อ่านเรื่องให้จบ&quot; ปลุกสมรรถนะการอ่าน ปลุกการเรียนรู้สู่การพัฒนาสมรรถนะการอ่านขั้นสูง&quot;</p>\r\n\r\n<p>ด้วยวีดิทัศน์การพัฒนาสมรรถนะการอ่านขั้นสูงสำหรับนักเรียนชั้นมัธยมศึกษาตอนต้นผ่านการจัดการเรียนรู้เชิงรุก (Active Learning)</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>หลังจากชมวีดิทัศน์แล้วรบกวนทำแบบสอบถามให้ด้วยนะคะ ขอบคุณค่ะ <a href=\"https://forms.gle/UEiVwVUmTXDASRmY7?fbclid=IwZXh0bgNhZW0CMTAAYnJpZBExS1VlbjlwS25vYTBFenVPSHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR70Ho3dojgNCcrkpMgyv1xQArk9TYptRd2DQZ6UCWH_zuzHAvDs2fr8zWLEmw_aem_3qGK3uIQNydWPC1OBHM5XA\" target=\"_blank\">https://forms.gle/UEiVwVUmTXDASRmY7</a></p>\r\n\r\n<h1>&nbsp;</h1>\r\n\r\n<h2><a href=\"https://www.facebook.com/profile.php?id=100075714378865&amp;sk=reels_tab&amp;__cft__[0]=AZaHiLFOWvb2IyJnLtAWh8IJUwFT4zSOnwgnIPap8gm8q1TlrsDduv4YlebYjsfjCAH9DGhy0YY3tjI6dF77OQZKgmRbAyrhn781gHiTnfla6A2ZGRnAkxRXDxQ0xi2vQVt9lEhzPTbp_HipiFzwf5uW7PhNLPP2Xz2qB1Nrs1M3xw&amp;__tn__=-]F\" target=\"_blank\">สถาบันภาษาไทย สำนักวิชาการและมาตรฐานการศึกษา สพฐ.</a></h2>\r\n\r\n<p>&nbsp;</p>\r\n', 'Upload', 1, '41.32 MB', 13, '2025-12-11 10:42:32'),
(113, 6, ' เพลงเด็กฟังยาวๆ | เป็ดอาบน้ำในคลอง ช้าง ลิง กุ๊กไก่ กบ | เปิดฟังยาวๆเพลินๆเลยจ้า', 'https://www.youtube.com/watch?v=PlVV2QdudjA', 'PlVV2QdudjA', '1766117356_เพลงเด็กฟังยาวๆ - เป็ดอาบน้ำในคลอง ช้าง ลิง กุ๊กไก่.jpg', '99:99:99', '<p><img alt=\"\" src=\"https://i.ytimg.com/vi/PlVV2QdudjA/hqdefault.jpg\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;#เพลงเด็กอนุบาล #เพลงเป็ด #เพลงเด็กในตำนาน<br />\r\nเป็ดอาบน้ำในคลอง / ไก่ กุ๊ก กุ๊ก ไก่ / เต่าเอ๋ยเต่า / นกเขาบินข้ามเขา / กบเอยทำไมจึงร้อง<br />\r\nอึ่งอ่างมานั่งข้างโอ่ง / ม้า วิ่ง กรับ กรับ / จับปูดำขยำปูนา / แมงมุมลายตัวนั้น / ลิง เจี๊ยก เจี๊ยก<br />\r\n&hellip;.<br />\r\nฟังเพลงเพิ่มเติมในช่อง<br />\r\nเพลงเด็กรวมฮิต เป็ด ช้าง ลิง กบ กุ๊กไก่ เต่า แมงมุมลาย<br />\r\nhttps://www.youtube.com/watch?v=bsxTR...<br />\r\nสื่อการเรียนการสอน กไก่ / &nbsp;ABC / 7 วัน 7 สี / 1ปีมี 12 เดือน<br />\r\nhttps://www.youtube.com/watch?v=AcLn8...<br />\r\nเพลงเด็กภาษาอังกฤษ 5 little duck / Wheels On The Bus &nbsp;/Baby Shark<br />\r\nhttps://www.youtube.com/watch?v=64M5W...</p>\r\n\r\n<p><br />\r\nช่องเพลงเด็ก<br />\r\nสนับสนุนพัฒนาการเด็กไทย<br />\r\nเพื่อให้เรียนรู้เกี่ยวกับ เพลง และ สัตว์ ต่างๆ<br />\r\nเป็ด ลิง กบ ช้าง เต่า แมงมุม<br />\r\nเราทำเป็นเพลงออกมามากมายเพื่อให้เรียนรู้<br />\r\nผ่านเพลงได้ง่าย ส่งเสริมพัฒนาการ และอารมณ์<br />\r\nของเด็กไทย มีทั้งเพลงช้าง เพลงเป็ด เพลงเต่า<br />\r\nเพลงกบเอยทำไมจึงร้อง เพลงรถไฟ เพลงแมงมุมลาย<br />\r\nเพลงหนอนผีเสื้อ เพลงลิงเจี๊ยก เจี๊ยก และยังมี<br />\r\nเพลงสำหรับกล่อมนอน เพลงฟังก่อนนอน<br />\r\nเพลงกล่อมเด็กอีกด้วย ทั้งเพลง นกขมิ้นเหลืองอ่อน<br />\r\nเพลง เจ้านกกาเหว่าเอย อีกทั้งเพลงพื้นบ้าน<br />\r\nก็มีให้ฟังเพื่อร่วมอนุรักษ์วัฒนธรรมพื้นบ้านสืบไป<br />\r\nเช่น เพลงรีรี ข้าวสาร เพลงแม่งูเอ๋ย กินน้ำบ่อไหน<br />\r\nทั้งเด็กอนุบาล เด็กก่อนวัยเรียน เด็กปฐมวัย<br />\r\nจะได้เรียนรู้ไปพร้อมๆกัน<br />\r\n&nbsp; เพลงเด็ก ช่องเรา เป็น เพลงฮิต ที่ได้รับความนิยม<br />\r\nเป็น เพลงเด็กอนุบาล มีทั้งเพลงไทย และเพลงสากล<br />\r\nเรามี เพลงภาษาอังกฤษ ให้เด็กได้เรียนรู้ด้วย<br />\r\n#เพลงเด็กอนุบาล #เพลงเป็ด #เพลงเด็กในตำนาน<br />\r\n&nbsp;</p>\r\n', 'Youtube', 1, '', 4, '2025-12-18 21:09:16'),
(114, 6, 'ก เอ๋ย ก ไก่ (ฉบับอนุบาล) 🐔 ฝึกท่อง ก-ฮ ร้องตามง่าย ภาพการ์ตูน 3D | SUNZEN KIDS', 'https://www.youtube.com/watch?v=KQiiQZKm2uU', 'KQiiQZKm2uU', '1766118033_hqdefault.jpg', '2:26', '<p>&nbsp;</p>\r\n\r\n<p>ก เอ๋ย ก ไก่ (ฉบับอนุบาล) 🐔 ฝึกท่อง ก-ฮ ร้องตามง่าย ภาพการ์ตูน 3D | SUNZEN KIDS</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"https://i.ytimg.com/vi/KQiiQZKm2uU/hqdefault.jpg\" /></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<hr />\r\n<p>มาแล้วจ้า! เพลง ก เอ๋ย ก ไก่ ฉบับเด็กอนุบาลร้องประสานเสียงสุดน่ารัก! 🎶🎓 SUNZEN KIDS MELODY ชวนน้องๆ มาฝึกท่องพยัญชนะไทยทั้ง 44 ตัว ตั้งแต่ ก.ไก่ ถึง ฮ.นกฮูก ไปพร้อมๆ กับเพื่อนๆ ในห้องเรียน</p>\r\n\r\n<p>คลิปนี้มาพร้อมกับภาพการ์ตูน 3D Animation สีสันสดใส ตัวการ์ตูนน่ารัก ดุ๊กดิ๊ก ช่วยให้น้องๆ จำตัวอักษรได้ง่ายขึ้นและสนุกกับการเรียนรู้ เหมาะสำหรับเปิดให้น้องๆ ฝึกร้องตามที่บ้าน หรือคุณครูใช้เปิดประกอบการสอนในห้องเรียนก็ได้นะครับ</p>\r\n\r\n<p>📝 เนื้อเพลง ก เอ๋ย ก ไก่ (Lyrics):<br />\r\nก เอ๋ย ก ไก่ ข ไข่ อยู่ในเล้า ฃ ขวด ของเรา ค ควาย เข้านา</p>\r\n\r\n<p>ฅ คน ขึงขัง ฆ ระฆัง ข้างฝา ง งู ใจกล้า จ จาน ใช้ดี</p>\r\n\r\n<p>ฉ ฉิ่ง ตีดัง ช ช้าง วิ่งหนี ซ โซ่ ล่ามที ฌ เฌอ คู่กัน</p>\r\n\r\n<p>ญ หญิง โสภา ฎ ชฎา สวมพลัน ฏ ปฏัก หุนหัน ฐ ฐาน เข้ามารอง</p>\r\n\r\n<p>ฑ นางมณโฑ หน้าขาว ฒ ผู้เฒ่า เดินย่อง ณ เณร ไม่มอง ด เด็ก ต้องนิมนต์</p>\r\n\r\n<p>ต เต่า หลังตุง ถ ถุง แบกขน ท ทหาร อดทน ธ ธง คนนิยม</p>\r\n\r\n<p>น หนู ขวักไขว่ บ ใบไม้ ทับถม ป ปลา ตากลม ผ ผึ้ง ทำรัง</p>\r\n\r\n<p>ฝ ฝา ทนทาน พ พาน วางตั้ง ฟ ฟัน สะอาดจัง ภ สำเภา กางใบ</p>\r\n\r\n<p>ม ม้า คึกคัก ย ยักษ์ เขี้ยวใหญ่ ร เรือ พายไป ล ลิง ไต่ราว</p>\r\n\r\n<p>ว แหวน ลงยา ศ ศาลา เงียบเหงา ษ ฤๅษี หนวดยาว ส เสือ ดาวคะนอง</p>\r\n\r\n<p>ห หีบ ใส่ผ้า ฬ จุฬา ท่าผยอง อ อ่าง เนืองนอง ฮ นกฮูก ตาโต<br />\r\n🌟 อย่าลืมกดติดตามช่อง SUNZEN KIDS MELODY เพื่อดูการ์ตูนใหม่ๆ: 👉 Youtube: &nbsp; &nbsp;/ @sunzenkids &nbsp;</p>\r\n\r\n<p>ขอบคุณที่รับชมครับ! ❤️</p>\r\n\r\n<p>#กเอ๋ยกไก่ #เพลงเด็ก #ฝึกอ่านไทย #ThaiAlphabet #เพลงเด็กอนุบาล #SUNZENKIDS #สื่อการสอนปฐมวัย #การ์ตูน3D #เรียนภาษาไทย<br />\r\ncr :&nbsp;<a href=\"https://www.youtube.com/@sunzenkids\"><img alt=\"\" src=\"https://yt3.ggpht.com/WOFvuF0rivtmOZsr5q5Vlmn3sQGqKht83-jARizAE1x2Z9xArG9Bp95WvlMSlNN2u1sH7Hxy=s88-c-k-c0x00ffffff-no-rj\" style=\"width:40px\" /></a></p>\r\n\r\n<p><a href=\"https://www.youtube.com/@sunzenkids\">SUNZEN KIDS MELODY</a></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n', 'Youtube', 1, '', 0, '2025-12-18 21:20:33'),
(115, 6, '[FB] อ่านจับตา นวัตกรรมเพื่อพัฒนาทักษะเริ่มต้นการอ่านจับใจความ', '1766647610_อ่านจับตา นวัตกรรมเพื่อพัฒนาทักษะเริ่มต้นการอ่านจับใจความ.mp4', 'cda11up', '1766647610_อ่านจับตา นวัตกรรมเพื่อพัฒนาทักษะเริ่มต้นการอ่านจับใจความ.jpg', '12:02', '<p><a href=\"https://web.facebook.com/watch/hashtag/%E0%B8%AD%E0%B9%88%E0%B8%B2%E0%B8%99%E0%B8%88%E0%B8%B1%E0%B8%9A%E0%B8%95%E0%B8%B2?__eep__=6%2F&amp;__tn__=*NK\">#อ่านจับตา</a></p>\r\n\r\n<p>นวัตกรรมเพื่อพัฒนาทักษะเริ่มต้นการอ่านจับใจความ</p>\r\n\r\n<p>- ผลที่ได้น่าพึงพอใจดังนี้</p>\r\n\r\n<p>1.ผู้เรียน ไม่กลัวการอ่านเรื่องตอบคำถาม (มองเป็นเกมจับตา)</p>\r\n\r\n<p>2.ผู้เรียนได้ทักษะการหาคำตอบ จากโจทย์ตรงตามจุดประสงค์การสร้างนวัตกรรม</p>\r\n\r\n<p>3.ผู้เรียน เลิกนิสัยขี้เกียจอ่านโจทย์ / เลิกเดาตอบทันที</p>\r\n\r\n<p>4.ผู้เรียนส่วนใหญ่มีผลการทดสอบได้เต็ม 10 คะแนน</p>\r\n\r\n<p>และที่เหลือเกาะกลุ่มในช่วง 9 8 7 ทั้งหมด</p>\r\n\r\n<p>(มีเพียง 2 คนที่ได้ต่ำคือ 5 กับ 3 ต้องพัฒนาต่อไป)</p>\r\n\r\n<p>5.ผู้เรียนสนุกและมีความสุขในการเรียน&nbsp;<img alt=\"♥\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tac/1/16/2665.png\" style=\"height:16px; width:16px\" />&nbsp;<img alt=\"♥\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tac/1/16/2665.png\" style=\"height:16px; width:16px\" />&nbsp;<img alt=\"♥\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tac/1/16/2665.png\" style=\"height:16px; width:16px\" />&nbsp;&lt;ข้อนี้สำคัญสุดครับ</p>\r\n\r\n<p><a href=\"https://web.facebook.com/watch/hashtag/%E0%B8%AD%E0%B9%88%E0%B8%B2%E0%B8%99%E0%B8%AD%E0%B8%AD%E0%B8%81%E0%B9%80%E0%B8%82%E0%B8%B5%E0%B8%A2%E0%B8%99%E0%B9%84%E0%B8%94%E0%B9%89?__eep__=6%2F&amp;__tn__=*NK\">#อ่านออกเขียนได้</a>&nbsp;<a href=\"https://web.facebook.com/watch/hashtag/%E0%B8%8B%E0%B9%88%E0%B8%AD%E0%B8%A1%E0%B8%9A%E0%B8%B1%E0%B8%99%E0%B9%84%E0%B8%94%E0%B8%A0%E0%B8%B2%E0%B8%A9%E0%B8%B2?__eep__=6%2F&amp;__tn__=*NK\">#ซ่อมบันไดภาษา</a></p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>ดาวน์โหลด :&nbsp;<a href=\"https://drive.google.com/file/d/1Qm54hYX8-tsm6Fezqtwjmq8eei